import { BrowserRouter, Routes, Route } from "react-router-dom";
import Registration from "./registration";
import Mainweatherpage from "./mainweatherpage";
import Login from "./login"
import Convertmain from "./convertmain";
import Movies from "./movies";
import Crypto from "./crypto";
import News from "./news";
import Newsview from "./newsview";
import Verification from "./verification";
import { useEffect, useState } from "react"
function App() {
    let [sessionres, changesessionres] = useState()
      useEffect(() => {
        console.log(Math.random().toString(16).substring(2))
          async function checksession() {
              let response = await fetch("http://localhost:5000/checksession", {
                  method: "GET",
                  headers: {"Content-Type":"application/json"},
                  credentials: "include"
              })
              let responsebool = await response.json()
              changesessionres(responsebool)
              }
          checksession()
          console.log("Session check completed. Result:", sessionres)
  }, [])
  return <>
  <BrowserRouter>
    <Routes>
      <Route path="/" element={<Registration/>}/>
      <Route path="/login" element={<Login/>}/>
      {sessionres && sessionres == false ? <Route path="/weather" element={<div className="notloggedin">
            <h1>You are not logged in {sessionres}</h1>
            <p>Please log in to view the weather</p>
        </div>}/> : <Route path="/weather" element={<Mainweatherpage/>}/>}
      {sessionres == false ? <Route path="/currencyconvert" element={<div className="notloggedin">
            <h1>You are not logged in {sessionres}</h1>
            <p>Please log in to view the currency converter</p>
        </div>}/> : <Route path="/currencyconvert" element={<Convertmain/>}/>}
      {sessionres == false ? <Route path="/movies" element={<div className="notloggedin">
            <h1>You are not logged in {sessionres}</h1>
            <p>Please log in to view the movies</p>
        </div>}/> : <Route path="/movies" element={<Movies/>}/>}
      {sessionres == false ? <Route path="/crypto" element={<div className="notloggedin">
            <h1>You are not logged in {sessionres}</h1>
            <p>Please log in to view the crypto news</p>
        </div>}/> : <Route path="/crypto" element={<Crypto/>}/>}
      {sessionres == false ? <Route path="/news" element={<div className="notloggedin">
            <h1>You are not logged in {sessionres}</h1>
            <p>Please log in to view the news</p>
        </div>}/> : <Route path="/news" element={<News/>}/>}
      {sessionres == false ? <Route path="/newsview" element={<div className="notloggedin">
            <h1>You are not logged in {sessionres}</h1>
            <p>Please log in to view the news</p>
        </div>}/> : <Route path="/newsview" element={<Newsview/>}/>}
      <Route path="/verifiedemail" element={<Verification/>}/>
    </Routes>
  </BrowserRouter>
  </>
}
export default App
